INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('rain', 'RAIN', 'mobile-networks', 63, 'GO WITH CAUTION', 'logos/rain.jpg', 'https://www.rain.co.za', $json$[{"category":"Compliance","score":"19/20","description":"ICASA licensed and compliant per 2024/25 report; no fines or violations in 2025/26. Past issues resolved."},{"category":"Customer Satisfaction","score":"10/25","description":"HelloPeter 2.37/5 (6,726 reviews), NPS -54; dominant complaints on service quality despite 100% response rate."},{"category":"Product Value","score":"22/30","description":"Competitive entry pricing and flexibility score well, but low satisfaction impacts perceived value."},{"category":"Innovation","score":"7/10","description":"Pioneered standalone 5G home, bundles with 4G mobile; no standout mobile innovations."},{"category":"Customer Support","score":"8/15","description":"Quick responses but poor resolution rates per reviews; mixed agent experiences."},{"category":"Accessibility & Security","score":"7/10","description":"Standard mobile security with no recent breaches since 2021 minor incident; POPIA compliant terms. Decent but unremarkable."}]$json$::jsonb, $json$["month-to-month contracts","4G voice/data/SMS bundles","5G home integration","national coverage"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: From R165/mo rainGO (2GB, 60mins, 100SMS), month-to-month","features":""}]$json$::jsonb, $json${"google_play":"2.81/5 (my rain app, 12k reviews); 4.2/5 (rain talk, 828 reviews)","ios":"No prominent iOS app found"}$json$::jsonb, $json$["competitive pricing","ICASA compliance","no contracts","high response rate"]$json$::jsonb, $json$["slow speeds","support resolution","outages"]$json$::jsonb, $json${"summary":"HelloPeter 2.37/5 poor; Trustpilot 4.3/5 mixed service focus","positive_themes":["affordable pricing","good agent interactions","reliable for some users"],"common_concerns":["slow speeds","poor support","outages"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('cell-c', 'Cell C', 'mobile-networks', 57, 'NOGO', 'logos/cell-c.jpg', 'https://www.cellc.co.za', $json$[{"category":"Compliance","score":"14/20","description":"ICASA approved Blue Label ownership transfer Jan 2025; fined R500k by National Consumer Tribunal for CPA violation on roaming overcharges; data breach reported but no POPIA fine noted."},{"category":"Customer Satisfaction","score":"10/20","description":"Low ratings across platforms: Trustpilot 1.7/5, PissedConsumer 1.7/5, app stores mixed; complaints dominate on service failures despite some coverage improvements."},{"category":"Product Value","score":"25/30","description":"Competitive low pricing beats MTN/Vodacom on cost (e.g. cheaper data bundles); good value for budget users but coverage/speed reliant on partners."},{"category":"Innovation","score":"7/10","description":"Asset-light roaming on MTN/Vodacom for LTE coverage; 5G launch imminent 2025; MVNO hosting growth (FNB, Capitec); refreshed app with OTP login, balances; rebranded 2024."},{"category":"Customer Support","score":"6/15","description":"Frequent complaints on unresponsive support, long waits, unhelpful agents, poor resolution (WhatsApp, phone, stores); some positive store experiences."},{"category":"Accessibility & Security","score":"4/10","description":"Recent ransomware data breach exposed customer data; POPIA compliance unconfirmed but incident raises concerns on security practices; app access ok but low ratings suggest usability issues; no specific inclusivity info."}]$json$::jsonb, $json$["prepaid/postpaid plans","data bundles","LTE roaming coverage","FTTH fibre","MVNO hosting","device contracts"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Elevate+ from R229/mo (3GB), promos like 20GB R99; 1GB prepaid ~R65","features":""}]$json$::jsonb, $json${"google_play":"3.8/5","ios":"2.7/5"}$json$::jsonb, $json$["affordable pricing","improving coverage via partners","MVNO growth","financial turnaround"]$json$::jsonb, $json$["billing errors","poor support","data breach"]$json$::jsonb, $json${"summary":"Predominantly negative on reviews sites; complaints on service/billing outweigh positives on price/coverage.","positive_themes":["cheap data","improved network","helpful stores occasionally","value bundles"],"common_concerns":["poor customer service","billing disputes","contract cancellation issues","network outages","data breaches"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('mtn-south-africa', 'MTN South Africa', 'mobile-networks', 50, 'NOGO', 'logos/mtn.jpg', 'https://www.mtn.co.za', $json$[{"category":"Compliance","score":"16/20","description":"ICASA licensed operator, won 2025 High Court case against flawed ICASA broadband regs, no major fines or license issues in 2025-2026 found."},{"category":"Customer Satisfaction","score":"4/20","description":"HelloPeter 1.14/5 (5k reviews, 94% 1-star), Trustpilot 1.4/5; widespread complaints on service/billing."},{"category":"Product Value","score":"20/30","description":"Competitive plans w/bundles/deals, recent hikes (5.4% avg) but speed increases offset; good value on network perf."},{"category":"Innovation","score":"8/10","description":"Best mobile data network quality SA 2025/26 (9.96 score, top Speedtest 74Mbps); 5G rollout, 3G sunset 2026, MoMo fintech w/Mastercard."},{"category":"Customer Support","score":"4/15","description":"Consistently poor per reviews: long waits, unhelpful agents, endless transfers; channels include app, *135, WhatsApp, stores."},{"category":"Accessibility & Security","score":"6/10","description":"2025 cyber breach exposed some customer data but core financial systems secure; POPIA compliant framework in place, app security average."}]$json$::jsonb, $json$["prepaid/postpaid voice/data plans","home LTE/5G uncapped","MoMo mobile money","DataShare","self-service app"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Contracts from R115/mo (30GB), home uncapped from R339/mo (15Mbps); 5.4% hike Feb 2026 w/speed bonuses","features":""}]$json$::jsonb, $json${"google_play":"3.9/5","ios":"~2.5/5"}$json$::jsonb, $json$["top network speed/quality","wide coverage","5G adoption","fintech services"]$json$::jsonb, $json$["poor customer service","billing disputes","app functionality"]$json$::jsonb, $json${"summary":"Overwhelmingly negative on HelloPeter/Trustpilot re service/billing; positive network mentions.","positive_themes":["network performance","coverage","data speeds"],"common_concerns":["billing errors","poor support","contract cancellations","network outages","data delivery issues"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
