UX frustration on Trustpilot; no major SA complaints.","positive_themes":["innovation","reliability","growth","AI features"],"common_concerns":["usability issues","glitches","login problems"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('sage-hr-south-africa', 'Sage HR South Africa', 'hr-software', 85, 'GO', 'https://yt3.googleusercontent.com/bwah0-dqJvfZJ15Zdv8pkn9EqegyDIPeC8x9Ph_ofwHB17jtIALgoUiGEdaN2N2HoERbWcnq=s900-c-k-c0x00ffffff-no-rj', 'https://www.sage.com/en-za/hr', $json$[{"category":"Compliance","score":"18/20","description":"Established Sage provider with POPIA readiness program. No regulatory issues, fines, or complaints found in SA. Payroll/HR software implies labor law compliance via updates."},{"category":"Customer Satisfaction","score":"21/25","description":"Strong 4.3-4.5/5 on GetApp, Capterra, G2 (300+ reviews). Positive on ease, legislation updates. Limited HelloPeter (1 app complaint). Employee Indeed 4.0/5. No major SA complaints."},{"category":"Product Value","score":"30/35","description":"Modular pricing starts low for SMBs (under R25/emp core), good value with core features + add-ons. Transparent, no contracts, free trial. Covers full HR needs scalably."},{"category":"Innovation","score":"8/10","description":"Cloud platform with mobile app, automation for leave/expenses/performance, legislation auto-updates, self-service. Good for SMBs but no standout 2025/2026 AI/new tech noted."},{"category":"Customer Support","score":"13/15","description":"Phone/email/chat/live Q&A, 24/7 resources. Reviews rate 4.5-4.6/5 responsive; some SA payroll support critiques but overall strong."},{"category":"Accessibility & Security","score":"8/10","description":"Cloud-based access with mobile app for iOS/Android, self-service portal. POPIA compliance efforts ongoing since 2021; no breaches reported. Role-based access implied. Mixed app accessibility feedback."}]$json$::jsonb, $json$["leave management","timesheets","shift scheduling","expenses","performance reviews","recruitment"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Core + Leave from R24/emp/mo; add-ons R10-14/emp/mo, Recruitment R1850/mo","features":""}]$json$::jsonb, $json${"google_play":"3.7/5 (Sage Self Service, 501 reviews)","ios":"Limited data; complaints on functionality"}$json$::jsonb, $json$["user-friendly","auto legislation compliance","strong support","affordable modular pricing","mobile self-service","integration with Sage Payroll"]$json$::jsonb, $json$["mobile app issues","rigid modules","occasional slow dev fixes"]$json$::jsonb, $json${"summary":"Positive in software review sites (4.4+ avg). Limited HelloPeter/Google specific to SA; app complaints minor.","positive_themes":["easy to use","intuitive","great support","time-saving automation","legislation updates"],"common_concerns":["mobile app bugs","shift scheduling tricky","extra security steps slow"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('simplepay', 'SimplePay', 'hr-software', 88, 'GO', 'https://cdn.theorg.com/6838312f-f027-474f-a72a-f7a502c87a4a_medium.jpg', 'https://www.simplepay.co.za', $json$[{"category":"Compliance","score":"19/20","description":"Auto SARS/DoL compliance (PAYE/UIF/SDL/ETI), eFiling integration, legislative updates, no regulatory issues found."},{"category":"Customer Satisfaction","score":"21/25","description":"Strong ratings on Capterra/Xero (4.5-5/5), praises ease/support/compliance; limited HelloPeter data, low complaints."},{"category":"Product Value","score":"30/35","description":"Single all-features plan, transparent pay-as-you-go, good SME value despite no public prices."},{"category":"Innovation","score":"9/10","description":"Cloud/mobile self-service app, API/Xero integration, auto 2025 updates (e.g. ETI rates)."},{"category":"Customer Support","score":"13/15","description":"Free support praised as quick, knowledgeable, friendly; email/phone channels per reviews."},{"category":"Accessibility & Security","score":"9/10","description":"Strong security with 2FA, role-based access, POPIA statement, ISO 27001 in progress; mobile app ensures accessibility."}]$json$::jsonb, $json$["Automated tax/payroll calc","SARS eFiling","leave mgmt","self-service app","Xero/QuickBooks integration","custom items"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: ~R65 base + R18/emp/mo excl VAT","features":""}]$json$::jsonb, $json${"google_play":"N/A (Self-Service app exists, 50K+ downloads)","ios":"N/A"}$json$::jsonb, $json$["ease of use","SA compliance","affordability SMEs","strong support","integrations"]$json$::jsonb, $json$["complex payrolls","admin pricing"]$json$::jsonb, $json${"summary":"Positive reviews/news; praises ease/compliance/support; minor complex needs complaints.","positive_themes":["simple","compliant","time-saving","reliable support"],"common_concerns":["complex payroll limitations","occasional support delays for advanced issues"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('payspace-deel-local-payroll-powered-by-payspace', 'PaySpace (Deel Local Payroll, powered by PaySpace)', 'hr-software', 79, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.payspace.com&size=128', 'https://www.payspace.com', $json$[{"category":"Compliance","score":"19/20","description":"Automatic SARS compliance, POPIA/GDPR/LGPD compliant, ISO 27001 first in Africa for payroll, SOC1/2, no regulatory issues found, Deel backing. Excellent track record."},{"category":"Customer Satisfaction","score":"16/25","description":"Mixed: HelloPeter 2.33/5 (3 recent: 2 poor support, 1 excellent); high elsewhere (Trustpilot 4.6/5, SelectHub 98/100). Positive on ease/use, negative recent support."},{"category":"Product Value","score":"28/30","description":"Scalable value, transparent per-emp pricing, broad features/HR add-ons, strong for SA/multi-country but no exact ZAR. High value."},{"category":"Innovation","score":"9/10","description":"Cloud-native real-time payroll, WhatsApp ESS, API integrations (Workday/Xero), AI mentions, auto legislative updates, Deel acquisition expands to 45+ countries."},{"category":"Customer Support","score":"10/15","description":"Praised in most reviews (prompt, excellent), but recent HelloPeter complaints on slow/no response, unclear escalation. NPS 97 claimed."},{"category":"Accessibility & Security","score":"9/10","description":"Strong security with ISO 27001:2022 certification, SOC 1/2 compliance, POPIA/GDPR/LGPD, data residency options (SA/EU), 2FA/SSO, annual audits, penetration testing."}]$json$::jsonb, $json$["real-time payroll calculations","employee self-service (WhatsApp/mobile)","API integrations","automated compliance/SARS","HR modules (performance/recruitment)","multi-country support"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Pay-per-employee/month (no annual fees); Lite/Premier/Master plans; no specific ZAR listed","features":""}]$json$::jsonb, $json${"google_play":"Not found","ios":"Not found"}$json$::jsonb, $json$["compliance & security certifications","scalability (1-10k+ emp)","Deel backing/global reach","pay-per-employee transparent","seamless integrations"]$json$::jsonb, $json$["support delays","KPI/capture issues","EMP501 submission problems"]$json$::jsonb, $json${"summary":"No recent X posts found; review sites mixed recent (HelloPeter low, others high)","positive_themes":["user-friendly","accurate compliant payroll","excellent support (most)","reliable","transformative for SA legislation"],"common_concerns":["support response times","issue resolution","recent complaints on ticketing"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('orangehrm', 'OrangeHRM', 'hr-software', 83, 'GO', 'https://media.licdn.com/dms/image/v2/C560BAQFgTlJr2qeacg/company-logo_200_200/company-logo_200_200/0/1673255582482/orangehrm_logo?e=2147483647&v=beta&t=pk_j5FJfGClZ-Xnm5rFW5egIKtfH_Bjw8CGGYgA4408', 'https://www.orangehrm.com', $json$[{"category":"Compliance","score":"17/20","description":"No SA regulatory issues found; ISO 27001, GDPR; HR software not heavily regulated but POPIA-relevant security in place; clean track record."},{"category":"Customer Satisfaction","score":"20/25","description":"4.2/5 avg from 187+ Capterra/GetApp/SoftwareAdvice reviews; positives outweigh minor cons; no HelloPeter complaints found."},{"category":"Product Value","score":"28/30","description":"Free core option excellent value; modular paid adds flexibility but can increase costs; strong features for price."},{"category":"Innovation","score":"9/10","description":"Modular HRMS with mobile app, ATS, AI interview assistant, performance 360, roster drag-drop, integrations; active 2025 updates."},{"category":"Customer Support","score":"12/15","description":"Responsive, helpful per reviews (3.8-4.0/5); white glove implementation praised."},{"category":"Accessibility & Security","score":"9/10","description":"ISO 27001, GDPR compliant with MFA, role-based access, audit trails, backups; no explicit POPIA mention but general data security strong for HR data."}]$json$::jsonb, $json$["employee self-service","leave/PTO mgmt","recruitment ATS","performance reviews","time tracking","mobile app","reporting"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: Free Starter; Advanced custom quote (no public 2025/2026 ZAR pricing found)","features":""}]$json$::jsonb, $json${"google_play":"5.0/5 (86 reviews)","ios":"2.0/5 (5 ratings)"}$